mapper.insert:
	/*
		 SQL ID : SysCfgCtgrDAO.insert
		 설  명 : 설정 분류의 정보 등록
 	*/
	INSERT INTO TB_SYS_CFG_CTGR (
	       STNG_CTGRCD
	     , CTGRNM
	     , CTGR_EXPLN
	     , USEYN
	     , RGTR_ID
	     , FRST_INQ_DTTM
	     , MDFR_ID
	     , MOD_DTTM
	) VALUES (
	       #{cfgCtgrCd}
	     , #{ctgrNm}
	     , #{ctgrDesc}
	     , #{useYn}
		 , #{rgtrId}
		 , FN_DTTM()
		 , #{mdfrId}
		 , FN_DTTM()
	)

mapper.update:
	/*
		 SQL ID : SysCfgCtgrDAO.update
		 설  명 : 설정 분류의 정보 수정
 	*/
	UPDATE TB_SYS_CFG_CTGR
	   SET CTGRNM 	= #{ctgrNm}
	     , CTGR_EXPLN = #{ctgrDesc}
	     , USEYN = #{useYn}
	     , MOD_DTTM = FN_DTTM()
	     , MDFR_ID = #{mdfrId}
	 WHERE STNG_CTGRCD = #{cfgCtgrCd}

